void it_2725_Logic101_PickedUp(Item_GObj* gobj)
{
    Item* ip = gobj->user_data;
    PAD_STACK(0x18);
    Item_80268E5C(gobj, 0, ITEM_ANIM_UPDATE);
    ip->xDD4_itemVar.mewtwoshadowball.x50 = 0.0F;
}

